            organizerCertifiedAt: Record<string, never> | null;
            /** @description ISO-8601 when terms were last accepted */
            termsAcceptedAt: Record<string, never> | null;
            /** @description Version of terms last accepted */
            termsVersion: Record<string, never> | null;
            /** @description True when the user must accept current terms before using the app */
            requiresTermsAcceptance: boolean;
